515→  { code: 'fr', name: 'French', nativeName: 'Fran\u00e7ais', flag: '\ud83c\uddeb\ud83c\uddf7', dir: 'ltr' },
516→  { code: 'en', name: 'English', nativeName: 'English', flag: '\ud83c\uddec\ud83c\udde7', dir: 'ltr' },
